const name = 'Alice';
const greeting = "Hello, world!";
const message = `Welcome, ${name}!`;   // template literal — expression interpolation

// Strings are immutable
let s = 'hello';
s[0] = 'H';          // silently ignored — primitives are immutable
console.log(s);      // 'hello' — unchanged

s = 'Hello';         // OK — replacing the binding, not mutating

// Common string operations
'hello'.length          // 5
'hello'.toUpperCase()   // 'HELLO'
'hello world'.split(' ') // ['hello', 'world']
'hello'.includes('ell') // true
'hello'.slice(1, 3)     // 'el'
`${'  hello  '.trim()}` // 'hello'

const count = 42;
const price = 9.99;
const ratio = 1 / 3;  // 0.3333...

// Special number values
Infinity   // 1 / 0
-Infinity  // -1 / 0
NaN        // 'hello' * 2  — Not a Number (but typeof NaN === 'number'!)
Number.MAX_SAFE_INTEGER  // 9007199254740991 (2^53 - 1)
Number.MIN_SAFE_INTEGER  // -9007199254740991

// NaN is the only value not equal to itself
NaN === NaN   // false — use Number.isNaN() to check
Number.isNaN(NaN)   // true
Number.isNaN('NaN') // false — unlike global isNaN(), Number.isNaN() is strict

// Floating-point caution
0.1 + 0.2 === 0.3  // false — use Math.abs(a - b) < Number.EPSILON for comparisons
(0.1 + 0.2).toFixed(1) === '0.3' // true — format for display

const id1 = Symbol('id');
const id2 = Symbol('id');
id1 === id2   // false — every Symbol() call creates a unique value

const KEY = Symbol('key');
const obj = {};
obj[KEY] = 'value';
obj[KEY];     // 'value' — accessible only via this exact symbol reference

// Symbol.iterator — well-known symbol implementing the iterable protocol
class Range {
  constructor(start, end) { this.start = start; this.end = end; }
  [Symbol.iterator]() {
    let current = this.start;
    const end = this.end;
    return { next: () => current <= end
      ? { value: current++, done: false }
      : { value: undefined, done: true } };
  }
}
for (const n of new Range(1, 3)) console.log(n); // 1, 2, 3

const user = { id: 1, name: 'Alice', role: 'admin' };

// Property access
user.name;        // 'Alice' — dot notation
user['role'];     // 'admin' — bracket notation (required for dynamic keys)

// Spread — shallow copy
const copy = { ...user, role: 'viewer' };   // copy with overridden role

// Object.assign — also shallow
const merged = Object.assign({}, defaults, overrides);

// Computed property names
const key = 'status';
const state = { [key]: 'active' };  // { status: 'active' }

const items = ['a', 'b', 'c'];

// Mutation — changes the original array
items.push('d');          // add to end
items.pop();              // remove from end
items.splice(1, 1);       // remove at index 1

// Non-mutation — returns a new array (prefer in Angular)
const doubled = items.map(x => x + x);
const filtered = items.filter(x => x !== 'a');
const found  = items.find(x => x === 'b');
const index  = items.findIndex(x => x === 'b');
const sorted = [...items].sort();        // spread first to avoid mutating original

// Reduce
const total = [1, 2, 3].reduce((acc, n) => acc + n, 0);  // 6

// Spread
const combined = [...items, 'd', 'e'];

// Map — keyed collection
const map = new Map();
map.set('name', 'Alice');
map.set(42, 'forty-two');
map.get('name');   // 'Alice'
map.has(42);       // true
map.size;          // 2
for (const [key, value] of map) { console.log(key, value); }

// Set — unique values
const set = new Set([1, 2, 2, 3, 3]);
set.size;      // 3
set.has(2);    // true
set.add(4);
set.delete(1);
const uniqueArray = [...set]; // [2, 3, 4]

// Fast deduplication
const deduplicated = [...new Set(items)];

// Primitive type annotations
const name: string = 'Alice';
const age: number = 30;
const active: boolean = true;
const nothing: null = null;
const missing: undefined = undefined;

// Union types — one of several types
let id: string | number;
id = 'user-42';   // OK
id = 42;          // OK
// id = true;     // TypeScript error

// Literal types — only specific values
type Direction = 'north' | 'south' | 'east' | 'west';
let dir: Direction = 'north';
// dir = 'up';  // TypeScript error

// Arrays
const scores: number[] = [95, 87, 92];
const tags: Array<string> = ['angular', 'typescript'];

// Tuple — fixed-length, typed position
const point: [number, number] = [48.8, 2.3];

// Type inference — often you don't need to annotate
const inferred = 42;      // TypeScript infers: number
const items = ['a', 'b']; // TypeScript infers: string[]

function formatId(id: string | number): string {
  if (typeof id === 'string') {
    return id.toUpperCase();   // TypeScript knows id is string here
  }
  return id.toFixed(0);        // TypeScript knows id is number here
}

// instanceof guard
function processEvent(event: MouseEvent | KeyboardEvent) {
  if (event instanceof KeyboardEvent) {
    console.log(event.key);   // TypeScript knows it's KeyboardEvent
  }
}

// in guard
function render(shape: { radius: number } | { width: number; height: number }) {
  if ('radius' in shape) {
    // shape is the circle type
    console.log(Math.PI * shape.radius ** 2);
  }
}

@Component({
  selector: 'app-list',
  template: `<li *ngFor="let item of items">{{ item.name }}</li>`,
  changeDetection: ChangeDetectionStrategy.OnPush, // reference-based
})
export class ListComponent {
  @Input() items: Item[] = [];
}

// WRONG: mutating the array — Angular OnPush won't re-render
// this.items.push(newItem);        // same array reference
// this.items[0].name = 'Updated'; // same reference

// CORRECT: new array reference — Angular detects the change
this.items = [...this.items, newItem];          // spread creates a new array
this.items = this.items.map((item, i) =>
  i === 0 ? { ...item, name: 'Updated' } : item // new object reference
);

const original = { user: { name: 'Alice', scores: [95, 87] } };

// Shallow copy — nested objects still shared
const shallow = { ...original };
shallow.user.name = 'Bob';
console.log(original.user.name); // 'Bob' — same reference!

// Deep copy option 1: structuredClone (modern, handles more types)
const deep = structuredClone(original);
deep.user.name = 'Charlie';
console.log(original.user.name); // 'Alice' — independent

// Deep copy option 2: JSON round-trip (loses undefined, Date, functions, Maps)
const jsonCopy = JSON.parse(JSON.stringify(original));

// What structuredClone supports that JSON does not:
// Date, Map, Set, ArrayBuffer, RegExp, Infinity, undefined
const complex = {
  date: new Date(),
  map: new Map([['a', 1]]),
  set: new Set([1, 2, 3]),
  undef: undefined,
};
const cloned = structuredClone(complex); // works
// JSON.parse(JSON.stringify(complex)) would lose date, map, set, undef

// Shallow immutable update patterns used throughout Angular/NgRx

// Update one property — spread creates a new reference
const updatedUser = { ...user, name: 'Bob' };

// Update nested property
const updatedState = {
  ...state,
  user: { ...state.user, name: 'Bob' },
};

// Update one item in an array by index
const updatedItems = state.items.map((item, i) =>
  i === targetIndex ? { ...item, quantity: item.quantity + 1 } : item
);

// Remove an item from an array
const removedItem = state.items.filter(item => item.id !== idToRemove);

// Add to array
const addedItem = [...state.items, newItem];

// Multi-line strings
const html = `
  <div class="card">
    <h2>${title}</h2>
    <p>${description}</p>
  </div>
`.trim();

// Expression interpolation — any expression works
const result = `${Math.max(a, b)} is larger`;
const ternary = `Status: ${isActive ? 'active' : 'inactive'}`;

// Tagged template literals — function processes the template
function highlight(strings, ...values) {
  return strings.reduce((acc, str, i) =>
    acc + str + (values[i] !== undefined ? `<mark>${values[i]}</mark>` : ''), '');
}
const html2 = highlight`Hello ${name}, you have ${count} messages.`;
// 'Hello <mark>Alice</mark>, you have <mark>3</mark> messages.'

// Intl.NumberFormat — locale-aware formatting
const price = 1234567.89;
new Intl.NumberFormat('en-US', { style: 'currency', currency: 'USD' }).format(price);
// '$1,234,567.89'

new Intl.NumberFormat('de-DE', { style: 'currency', currency: 'EUR' }).format(price);
// '1.234.567,89 €'

// toFixed — rounds to decimal places (returns string)
(3.14159).toFixed(2)  // '3.14'
(1.005).toFixed(2)    // '1.00' — floating-point precision issue

// toPrecision — total significant digits
(123.456).toPrecision(5) // '123.46'

// Angular pipe equivalent
// {{ price | currency:'USD' }}
// {{ 0.42 | percent }}
// {{ 1234567 | number:'1.0-0' }}

// Optional chaining — short-circuits at null/undefined
const city = user?.address?.city;     // undefined if any step is null/undefined
const first = arr?.[0];               // undefined if arr is null/undefined
const result = fn?.();                // undefined if fn is null/undefined

// Nullish coalescing — fallback for null/undefined only (not 0 or '')
const name = user?.name ?? 'Guest';
const page = params.page ?? 1;

// Logical OR — fallback for any falsy (including 0, '')
const count = data.count || 0;  // 0 if data.count is 0 — usually wrong!
const count2 = data.count ?? 0; // 0 only if null/undefined — correct

// Non-null assertion — tells TypeScript "I know this isn't null"
const el = document.getElementById('app')!; // use sparingly

@Component({ ... })
export class ProfileComponent implements OnInit {
  // Without strict null checks (bad practice):
  user: User;  // TypeScript error in strict mode: not definitely assigned

  // With strict null checks (correct patterns):
  user: User | null = null;           // nullable, starts as null
  user2!: User;                       // definite assignment assertion (assigned in ngOnInit)
  user3: User | undefined = undefined; // undefined until loaded

  ngOnInit() {
    this.userService.getUser().subscribe(user => {
      this.user = user;
    });
  }
}

